-- Table: hardware_controllers
IF  EXISTS (SELECT * FROM sys.objects WHERE object_id = OBJECT_ID(N'[dbo].[hardware_controllers]') AND type in (N'U'))
DROP TABLE [dbo].[hardware_controllers]
