INSERT [dbo].[form_languages] ([form_id], [field_name], [field_desc1], [field_desc2], [field_desc3], [field_desc4], [field_desc5], [field_desc6], [field_desc7], [field_desc8], [field_desc9], [field_desc10], [parent_name], [is_form], [is_individual]) VALUES (9, N'lblEventLogDesc1', N'Older current event and alarm log displayed transaction will automatically be cleared upon reaching maximum rows. After cleared, only last events will be displayed.', N'Paparan transaksi log peristiwa dan log penggera akan dimuat turun secara automatik ketika sampai baris maksimum. Selepas refresh, hanya peristiwa terakhir akan dipaparkan.', N'Paparan transaksi log peristiwa dan alam semasa akan dimuat turun secara automatik ketika sampai baris maksimum. Selepas refresh, hanya peristiwa terakhir akan dipaparkan.', N'Sự kiện và nhật ký giao dịch báo động đã hiển thị  cũ hơn sẽ tự động bị xóa khi đạt đến các hàng tối đa. Sau khi xóa, chỉ các sự kiện cuối cùng mới được hiển thị.', N'سيتم تلقائيًا مسح سجل عمليات الأحداث والإنذارات الحالية الأقدم المعروضة عند الوصول إلى الحد الأقصى من الصفوف. بعد مسحها، سيتم عرض الأحداث الأخيرة فقط.', NULL, NULL, NULL, NULL, NULL, NULL, 0, 0)
GO
INSERT [dbo].[form_languages] ([form_id], [field_name], [field_desc1], [field_desc2], [field_desc3], [field_desc4], [field_desc5], [field_desc6], [field_desc7], [field_desc8], [field_desc9], [field_desc10], [parent_name], [is_form], [is_individual]) VALUES (9, N'lblEventLogDesc2', N'Following is to set the display rate of events. Display rate control how fast event are displayed.', N'Berikut adalah kadar paparan peristiwa. Kadar paparan berfungsi untuk mengawal kelajuan peristiwa dipaparkan.', N'Berikut adalah kadar paparan peristiwa. Kadar paparan berfungsi untuk mengawal kelajuan peristiwa dipaparkan.', N'Sau đây là cài đặt tốc độ tải về của các sự kiện. Hiển thị tốc độ tải sự kiện nhanh như thế nào.', N'فيما يلي تحديد معدل عرض الأحداث. التحكم في معدل العرض في مدى سرعة عرض الحدث.', NULL, NULL, NULL, NULL, NULL, NULL, 0, 0)
GO
INSERT [dbo].[form_languages] ([form_id], [field_name], [field_desc1], [field_desc2], [field_desc3], [field_desc4], [field_desc5], [field_desc6], [field_desc7], [field_desc8], [field_desc9], [field_desc10], [parent_name], [is_form], [is_individual]) VALUES (9, N'lblFace1', N'This is typically the IP address and port of the Server PC installed with MagServer. This setting should be uploaded to every reader to ensure they send data to the correct destination PC.', N'Ini biasanya alamat IP dan port PC Pelayan yang dipasang dengan MagServer. Tetapan ini harus dimuat naik ke setiap pembaca untuk memastikan mereka menghantar data ke PC destinasi yang betul.', N'Ini biasanya alamat IP dan port PC Server yang diinstal dengan MagServer. Pengaturan ini harus diunggah ke setiap pembaca untuk memastikan mereka mengirim data ke PC tujuan yang benar.', N'Đây thường là địa chỉ IP và cổng của Máy chủ được cài đặt với MagServer. Cài đặt này phải được tải lên mọi đầu đọc để đảm bảo họ gửi dữ liệu đến đúng PC đích.', N'عادةً ما يكون هذا هو عنوان IP والمنفذ الخاص بجهاز الكمبيوتر الخادم المثبت مع MagServer. يجب تحميل هذه الإعدادات إلى كل قارئ لضمان إرسال البيانات إلى الوجهة الصحيحة لجهاز الكمبيوتر', NULL, NULL, NULL, NULL, NULL, NULL, 0, 0)
GO
INSERT [dbo].[form_languages] ([form_id], [field_name], [field_desc1], [field_desc2], [field_desc3], [field_desc4], [field_desc5], [field_desc6], [field_desc7], [field_desc8], [field_desc9], [field_desc10], [parent_name], [is_form], [is_individual]) VALUES (9, N'lblFace2', N'Only applicable to face recognition reader with temperature sensor.', N'Hanya boleh digunakan untuk pembaca pengenalan wajah dengan sensor suhu.', N'Hanya berlaku untuk pembaca pengenalan wajah dengan sensor suhu.', N'Chỉ áp dụng cho đầu đọc nhận dạng khuôn mặt có cảm biến nhiệt độ.', N'ينطبق فقط على قارئ التعرف على الوجه المزود بمستشعر درجة الحرارة.', NULL, NULL, NULL, NULL, NULL, NULL, 0, 0)
GO
INSERT [dbo].[form_languages] ([form_id], [field_name], [field_desc1], [field_desc2], [field_desc3], [field_desc4], [field_desc5], [field_desc6], [field_desc7], [field_desc8], [field_desc9], [field_desc10], [parent_name], [is_form], [is_individual]) VALUES (9, N'lblFace3', N'This should be exactly the same as the max temperature set at the reader.  Temperature exceeding 37.5 is considered as fever.', N'Ini harus sama persis dengan suhu maksimum yang ditetapkan pada pembaca. Suhu melebihi 37.5 dianggap sebagai demam.', N'Ini harus persis sama dengan suhu maksimum yang disetel pada pembaca. Suhu melebihi 37,5 dianggap sebagai demam.', N'Điều này phải hoàn toàn giống với nhiệt độ tối đa được đặt ở đầu đọc. Nhiệt độ vượt quá 37,5 được coi là sốt.', N'يجب أن يكون هذا بالضبط نفس الحد الأقصى لدرجة الحرارة المحددة في القارئ. درجة الحرارة التي تزيد عن 37.5 تعتبر حمى.', NULL, NULL, NULL, NULL, NULL, NULL, 0, 0)
GO
