INSERT [dbo].[form_languages] ([form_id], [field_name], [field_desc1], [field_desc2], [field_desc3], [field_desc4], [field_desc5], [field_desc6], [field_desc7], [field_desc8], [field_desc9], [field_desc10], [parent_name], [is_form], [is_individual]) VALUES (193, N'lblMessage', N'Your software license is expired. Please kindly contact our authorized installer for activation key or new serial number in order to continue using this software. Our installer can response faster if you can send this screen shot that clearly show the serial number and MAC address to our authorized installer.', N'Lesen perisian anda tamat tempoh. Sila hubungi pemasang kami yang diberi kuasa untuk kekunci pengaktifan atau nombor siri baru untuk terus menggunakan perisian ini. Pemasang kami boleh bertindak balas lebih cepat jika anda boleh menghantar pukulan skrin ini yang dengan jelas menunjukkan nombor siri dan alamat MAC kepada pemasang kami yang diberi kuasa.', N'Lisensi perangkat lunak Anda telah kedaluwarsa. Silakan hubungi penginstal resmi kami untuk kunci aktivasi atau nomor seri baru untuk terus menggunakan perangkat lunak ini. Penginstal kami dapat merespons lebih cepat jika Anda dapat mengirim tangkapan layar ini yang dengan jelas menunjukkan nomor seri dan alamat MAC ke pemasang resmi kami.', N'Giấy phép phần mềm của bạn đã hết hạn. Vui lòng liên hệ với trình cài đặt được ủy quyền của chúng tôi để kích hoạt khóa hoặc số sê-ri mới để tiếp tục sử dụng phần mềm này. Trình cài đặt của chúng tôi có thể phản hồi nhanh hơn nếu bạn có thể gửi ảnh chụp màn hình này hiển thị rõ số sê-ri và địa chỉ MAC cho trình cài đặt được ủy quyền của chúng tôi.', N'انتهت صلاحية ترخيص البرنامج الخاص بك. يرجى التكرم بالاتصال بعامل التثبيت المعتمد لدينا للحصول على مفتاح التنشيط أو الرقم التسلسلي الجديد لمواصلة استخدام هذا البرنامج. يمكن أن يستجيب برنامج التثبيت لدينا بشكل أسرع إذا كان بإمكانك إرسال لقطة الشاشة هذه التي تعرض بوضوح الرقم التسلسلي وعنوان MAC إلى برنامج التثبيت المعتمد لدينا.', NULL, NULL, NULL, NULL, NULL, NULL, 0, 0)
GO
