INSERT [dbo].[form_languages] ([form_id], [field_name], [field_desc1], [field_desc2], [field_desc3], [field_desc4], [field_desc5], [field_desc6], [field_desc7], [field_desc8], [field_desc9], [field_desc10], [parent_name], [is_form], [is_individual]) VALUES (203, N'lblNote', N'Each group will have local nesting group among all selected Entry and Exit readers in the same group. Multiple groups can cater to different local nesting at different locations. PC must be turned on all the time for this function.', N'Setiap kumpulan akan mempunyai kumpulan bersarang tempatan di kalangan semua pembaca Kemasukan dan Keluar yang dipilih dalam kumpulan yang sama. Berbilang kumpulan boleh memenuhi sarang tempatan yang berbeza di lokasi yang berbeza. PC mesti dihidupkan sepanjang masa untuk fungsi ini.', N'Mỗi nhóm sẽ có nhóm lồng nhau cục bộ trong số tất cả các trình đọc Nhập và Thoát đã chọn trong cùng một nhóm. Nhiều nhóm có thể phục vụ cho việc làm tổ cục bộ khác nhau tại các địa điểm khác nhau. PC phải luôn được bật cho chức năng này.', N'Mỗi nhóm sẽ có nhóm lồng nhau cục bộ trong số tất cả các trình đọc Nhập và Thoát đã chọn trong cùng một nhóm. Nhiều nhóm có thể phục vụ cho việc làm tổ cục bộ khác nhau tại các địa điểm khác nhau. PC phải luôn được bật cho chức năng này.', N'لكل مجموعة سيكون هناك مجموعة تداخل محلية بين جميع قارئات بطاقات الدخول والخروج المحددين في نفس المجموعة. يمكن لمجموعات متعددة تلبية احتياجات التداخل المحلية المختلفة في مواقع مختلفة. يجب تشغيل جهاز الكمبيوتر طوال الوقت لهذه الوظيفة.', NULL, NULL, NULL, NULL, NULL, NULL, 0, 0)
GO
