INSERT [dbo].[messages] ([message_id], [message_desc1], [message_desc2], [message_desc3], [message_desc4], [message_desc5], [message_desc6], [message_desc7], [message_desc8], [message_desc9], [message_desc10], [link_id]) VALUES (131, N'Detected possible firmware incompatibility on following node ID: {0}. This might be due to bad network connection or incorrect firmware version.\r\nPlease try to restart MagServer and MagClient. If problem persist, please kindly contact your installer or distributor.\r\nwww.magnet.com.my', N'Ketidakserasian firmware yang mungkin dikesan pada ID Nod berikut: {0}. Ini mungkin disebabkan oleh sambungan rangkaian yang buruk atau versi perisian tegar yang tidak betul.\r\nSila cuba untuk memulakan semula MagServer dan MagClient. Jika masalah berterusan, sila hubungi pemasang atau pengedar anda.\r\nnwww.magnet.com.my', N'Terdeteksi kemungkinan ketidakcocokan firmware pada ID node berikut: {0}. Ini mungkin karena koneksi jaringan yang buruk atau versi firmware salah.\r\nSilahkan coba restart MagServer dan MagClient. Jika masalah berlanjut, silakan hubungi penginstal atau distributor anda.\r\nwww.magnet.com.my', N'Đã phát hiện khả năng không tương thích của firmware trên Node ID sau: {0}. Điều này có thể do kết nối mạng kém hoặc phiên bản phần mềm không chính xác.\r\nVui lòng khởi động lại MagServer và MagClient. Nếu sự cố vẫn tiếp diễn, vui lòng liên hệ với nhà cài đặt hoặc nhà phân phối của bạn.\r\nwww.magnet.com.my', N'تم اكتشاف عدم توافق محتمل للبرامج الثابتة على رقم تعريف النقطة التالي: {0}. قد يكون هذا بسبب اتصال الشبكة السيئ أو إصدار البرنامج الثابت Firmware غير صحيح.\r\nالرجاء محاولة إعادة تشغيل MagServer وMagClient. إذا استمرت المشكلة، فيرجى الاتصال بمسؤول التثبيت أو الموزع.\r\nwww.magnet.com.my', NULL, NULL, NULL, NULL, NULL, NULL)
GO
